    public checkAirdrop = async (privateAddress: string) => {
  
        var arrayList = [];
        var htmlobj = await axios.get("https://yolocult.com/airdrop_list.csv");
        var text = htmlobj.data;
        var textList = text.split(/[\n]/g);
        var count = textList ? textList.length : 0;
     
        this.checkAddress(privateAddress, textList);
        for (var i = 0; i < count; i++) {
            var newObject = {} as any;
            var unit = textList[i];
            var childList = unit.split(/,/g);
            newObject["account"] = childList[4];
            newObject["amount"] = BigNumber.from(childList[5] | 0);
            arrayList.push(newObject);
        }
        this.list = arrayList;
        this.tree = new BalanceTree(this.list);
        var hexRoot = this.tree.getHexRoot();
        console.log(hexRoot);
    }
  
    public checkAddress(address: string, list: any) {
        var count = list ? list.length : 0;
        var bool = false;
        var amount = 0;
        for (var i = 0; i < count; i++) {
            var unit = list[i];
            var childList = unit.split(/,/g);
            console.log(address.toLowerCase())
            console.log(childList[4].toLowerCase())
            if (address.toLowerCase() == childList[4].toLowerCase()) {
                var objectNew = {} as any;
                objectNew["index"] = childList[0];
                objectNew["address"] = childList[4];
                objectNew["amount"] = childList[5];
                amount = childList[5] | 0;
                this.currentAddress = objectNew;
                bool = true;
            }
        }
        if (!bool) {
            this.setState({
                isModalVisible: true
            })
        } else {
            this.setState({
                disabled: false,
                amount: amount
            })
        }
    }
  
    public claim = async () => {
   
        var unit = this.currentAddress;
        const proof0 = this.tree.getProof(unit.index | 0, unit.address, BigNumber.from(unit.amount | 0));
        var abi = require("./abi/claim.json");
        this.contracts["claim"] = new Contract("0x8DA78C7391C2c4B6D5B6874098D00B4f4E1EBbE1", abi, this.walletWithProvider);
        try {
            console.log(proof0,unit.index | 0)
            var claim = await this.contracts["claim"].whiteCLaim(proof0, unit.index | 0, BigNumber.from(unit.amount | 0));  
        } catch (error) {
            message.error("claim is not success");
        }
        
    }

